mapper.select:
SELECT t1.id, t1.module, t1.action_type AS actionType, t1.title, t1.content, t1.operator_id AS operatorId, t1.operator_name AS operatorName, t1.request_uri AS requestUri, t1.request_method AS requestMethod, t1.ip, CONCAT(t1.province, " ", t1.city) AS region, t1.device, t1.os, t1.browser, t1.status, t1.execution_time AS executionTime, t1.error_msg AS errorMsg, t1.create_time AS createTime FROM sys_log t1
AND ( t1.title LIKE concat('%',#{queryParams.keywords},'%') OR t1.content LIKE concat('%',#{queryParams.keywords},'%') OR t1.ip LIKE concat('%',#{queryParams.keywords},'%') OR t1.operator_name LIKE concat('%',#{queryParams.keywords},'%') )
AND t1.create_time >= #{startDate}
AND t1.create_time <= #{endDate}
ORDER BY t1.create_time DESC
